import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [displayText, setDisplayText] = useState('');
  const navigate = useNavigate();

  const fullTitle = isLogin ? 'WELCOME TO CORTEX' : 'NEW ANALYST REGISTRATION';

  // Typewriter Effect
  useEffect(() => {
    let i = 0;
    setDisplayText('');
    const typing = setInterval(() => {
      if (i < fullTitle.length) {
        setDisplayText((prev) => prev + fullTitle.charAt(i));
        i++;
      } else {
        clearInterval(typing);
      }
    }, 70);
    return () => clearInterval(typing);
  }, [isLogin]);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => navigate('/dashboard'), 1500);
  };

  return (
    <div style={styles.container}>
      {/* 🚀 ANIMATED BACKGROUND ELEMENTS */}
      <div className="scanline"></div>
      <div className="cyber-wing left-wing"></div>
      <div className="cyber-wing right-wing"></div>

      <div style={styles.card}>
        <div style={styles.header}>
          <div style={styles.glitchContainer}>
            <h1 style={styles.title}>{displayText}<span className="cursor">_</span></h1>
          </div>
          <p style={styles.subtitle}>
            {isLogin ? 'AUTHENTICATION REQUIRED' : 'ESTABLISH NEW NODE CREDENTIALS'}
          </p>
        </div>

        <form onSubmit={handleSubmit} style={styles.form}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>CREDENTIAL ID</label>
            <input type="email" placeholder="admin@cortex.ai" style={styles.input} required />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>SECURITY PASSKEY</label>
            <input type="password" placeholder="••••••••" style={styles.input} required />
          </div>

          <button type="submit" style={styles.mainBtn}>
            {loading ? 'SYNCING...' : (isLogin ? 'INITIALIZE SYSTEM' : 'CREATE NODE')}
          </button>
        </form>

        <div style={styles.divider}>SECURE GATEWAY</div>

        <div style={styles.socialGroup}>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/color/18/000000/google-logo.png" alt="" /> GOOGLE_AUTH
          </button>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/ios-filled/18/ffffff/github.png" alt="" /> GITHUB_KEY
          </button>
        </div>

        <div style={styles.footer}>
          {isLogin ? "NEW ANALYST?" : "EXISTING ANALYST?"} 
          <span style={styles.toggle} onClick={() => setIsLogin(!isLogin)}>
            {isLogin ? ' [REGISTER]' : ' [LOGIN]'}
          </span>
        </div>
      </div>

      {/* CSS ANIMATIONS */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&display=swap');

        .scanline {
          width: 100%;
          height: 100px;
          z-index: 5;
          background: linear-gradient(0deg, rgba(0, 255, 157, 0) 0%, rgba(0, 255, 157, 0.1) 50%, rgba(0, 255, 157, 0) 100%);
          opacity: 0.1;
          position: absolute;
          bottom: 100%;
          animation: scan 4s linear infinite;
        }

        .cyber-wing {
          position: absolute;
          width: 30%;
          height: 100%;
          top: 0;
          background-image: url('https://www.transparenttextures.com/patterns/carbon-fibre.png');
          opacity: 0.05;
          pointer-events: none;
        }

        .left-wing {
          left: 0;
          border-right: 1px solid rgba(0, 255, 157, 0.2);
          background: linear-gradient(90deg, rgba(0,255,157,0.05) 0%, rgba(0,0,0,0) 100%);
        }

        .right-wing {
          right: 0;
          border-left: 1px solid rgba(0, 255, 157, 0.2);
          background: linear-gradient(-90deg, rgba(0,255,157,0.05) 0%, rgba(0,0,0,0) 100%);
        }

        .cursor { animation: blink 1s infinite; color: #00ff9d; }

        @keyframes scan {
          from { bottom: 100%; }
          to { bottom: -100px; }
        }

        @keyframes blink {
          50% { opacity: 0; }
        }
      `}</style>
    </div>
  );
};

const styles = {
  container: {
    backgroundColor: '#05070a',
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: "'Share Tech Mono', monospace",
    position: 'relative',
    overflow: 'hidden'
  },
  card: {
    width: '400px',
    backgroundColor: 'rgba(15, 20, 28, 0.95)',
    borderRadius: '4px',
    padding: '40px',
    boxShadow: '0 0 50px rgba(0, 255, 157, 0.1)',
    zIndex: 10,
    border: '1px solid rgba(0, 255, 157, 0.3)',
    position: 'relative'
  },
  header: { textAlign: 'left', marginBottom: '30px' },
  title: { color: '#00ff9d', fontSize: '22px', margin: '0', height: '30px' },
  subtitle: { color: '#475569', fontSize: '11px', letterSpacing: '2px', marginTop: '5px' },
  inputGroup: { marginBottom: '20px' },
  label: { display: 'block', color: '#94a3b8', fontSize: '10px', marginBottom: '8px', fontWeight: 'bold' },
  input: {
    width: '100%',
    padding: '12px',
    backgroundColor: '#0a0d12',
    border: '1px solid #1e293b',
    borderRadius: '2px',
    color: '#00ff9d',
    outline: 'none',
    boxSizing: 'border-box',
    fontFamily: "'Share Tech Mono', monospace"
  },
  mainBtn: {
    width: '100%',
    padding: '14px',
    backgroundColor: '#00ff9d',
    color: '#05070a',
    border: 'none',
    borderRadius: '2px',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '14px',
    boxShadow: '0 0 15px rgba(0, 255, 157, 0.3)'
  },
  divider: { textAlign: 'center', color: '#1e293b', margin: '20px 0', fontSize: '10px', borderBottom: '1px solid #1e293b', lineHeight: '0.1em' },
  socialGroup: { display: 'flex', gap: '10px' },
  socialBtn: {
    flex: 1,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px',
    padding: '10px',
    backgroundColor: 'transparent',
    border: '1px solid #1e293b',
    color: '#94a3b8',
    cursor: 'pointer',
    fontSize: '12px'
  },
  footer: { textAlign: 'center', marginTop: '25px', color: '#475569', fontSize: '12px' },
  toggle: { color: '#00ff9d', cursor: 'pointer' }
};

export default LoginPage;
